const language = ['../resources/C++.png'];

const LanguageList = () => {

    return(
        language.map(item=>{

                <div className="grid assessmentContent">
                    <div className="cell">
                        <div className="ui small image" style={{borderRadius:"50%",padding: "0em", maxHeight:"2rem",maxWidth:"2rem",zIndex:"5"}}>
                            <img src={require({item})} alt="CPlus"/>
                        </div>
                    </div>
                    <div className="cell"><i className="check icon"></i></div>
                    <div className="cell"><i className="check icon"></i></div>
                    <div className="cell"><i className="check icon"></i></div>
                    <div className="cell"><i className="check icon"></i></div>
                    <div className="cell"><i className="check icon"></i></div>
                </div>

        })

    )
};

export default LanguageList;
